void demonstrateBasicPointers() {
 printf("=== Basic Pointer Operations ===\n");

 int x = 42;
 int *p = &x; // Initialize pointer with address of x

 printf("Value of x: %d\n", x);
 printf("Address of x: %p\n", (void*)&x);
 printf("Pointer p holds: %p\n", (void*)p);
 printf("Dereferencing p (*p): %d\n", *p);

 // Modify value through pointer
 *p = 100;
 printf("Value of x after *p = 100: %d\n", x);

 // NULL pointer demonstration
 int *nullPtr = NULL;
 if (nullPtr == NULL) {
 printf("Pointer is NULL (not pointing to valid memory)\n");
 }
 printf("\n");
}

void demonstratePointerArithmetic() {
 printf("=== Pointer Arithmetic ===\n");

 int arr[] = {10, 20, 30, 40, 50};
 int *p = arr; // Array name acts as pointer to first element

 printf("Array: ");
 for (int i = 0; i < 5; i++) {
 printf("%d ", arr[i]);
 }
 printf("\n");

 printf("Using pointer arithmetic:\n");
 printf("*p = %d\n", *p); // 10
 printf("*(p+1) = %d\n", *(p+1)); // 20
 printf("*(p+2) = %d\n", *(p+2)); // 30

 // Increment pointer
 p++;
 printf("After p++, *p = %d\n", *p); // 20

 // Pointer difference
 int *p1 = &arr[0];
 int *p2 = &arr[4];
 printf("Pointer difference (p2 - p1): %ld\n", (long)(p2 - p1)); // 4

 printf("Size of int: %zu bytes\n", sizeof(int));
 printf("\n");
}

void demonstrateMallocCalloc() {
 printf("=== malloc vs calloc ===\n");

 // malloc - memory NOT initialized (contains garbage)
 printf("malloc demonstration:\n");
 int *mallocArr = (int *)malloc(5 * sizeof(int));
 if (mallocArr == NULL) {
 printf("Memory allocation failed!\n");
 return;
 }
 printf("malloc values (uninitialized): ");
 for (int i = 0; i < 5; i++) {
 printf("%d ", mallocArr[i]);
 }
 printf("\n");

 // Initialize manually
 for (int i = 0; i < 5; i++) {
 mallocArr[i] = (i + 1) * 10;
 }
 printf("After initialization: ");
 for (int i = 0; i < 5; i++) {
 printf("%d ", mallocArr[i]);
 }
 printf("\n");
 free(mallocArr);
 mallocArr = NULL;

 // calloc - memory initialized to zero
 printf("\ncalloc demonstration:\n");
 int *callocArr = (int *)calloc(5, sizeof(int));
 if (callocArr == NULL) {
 printf("Memory allocation failed!\n");
 return;
 }
 printf("calloc values (zero-initialized): ");
 for (int i = 0; i < 5; i++) {
 printf("%d ", callocArr[i]);
 }
 printf("\n");
 free(callocArr);
 callocArr = NULL;

 printf("\n");
}

void demonstrateRealloc() {
 printf("=== realloc Demonstration ===\n");

 // Initial allocation for 3 integers
 int *arr = (int *)malloc(3 * sizeof(int));
 if (arr == NULL) {
 printf("Memory allocation failed!\n");
 return;
 }

 arr[0] = 10;
 arr[1] = 20;
 arr[2] = 30;
 printf("Original array (size 3): ");
 for (int i = 0; i < 3; i++) {
 printf("%d ", arr[i]);
 }
 printf("\n");

 // Reallocate to size 5
 int *temp = (int *)realloc(arr, 5 * sizeof(int));
 if (temp == NULL) {
 printf("Reallocation failed! Original pointer still valid.\n");
 free(arr);
 return;
 }
 arr = temp; // Assign new pointer

 // Initialize new elements
 arr[3] = 40;
 arr[4] = 50;

 printf("Reallocated array (size 5): ");
 for (int i = 0; i < 5; i++) {
 printf("%d ", arr[i]);
 }
 printf("\n");

 free(arr);
 arr = NULL;

 printf("\n");
}

void demonstrateStructPointers() {
 printf("=== Structure Pointers ===\n");

 struct Student s1 = {"Rahul", 101, 85.5};
 struct Student *ptr = &s1; // Pointer to structure

 // Using arrow operator (->)
 printf("Using arrow operator (ptr->):\n");
 printf("Name: %s\n", ptr->name);
 printf("Roll No: %d\n", ptr->rollNo);
 printf("Marks: %.1f\n", ptr->marks);

 // Equivalent using dereference
 printf("\nUsing dereference (*ptr).member:\n");
 printf("Name: %s\n", (*ptr).name);

 // Dynamic structure allocation
 printf("\nDynamic structure allocation:\n");
 struct Student *dynamicStudent = (struct Student *)malloc(sizeof(struct Student));
 if (dynamicStudent == NULL) {
 printf("Memory allocation failed!\n");
 return;
 }

 strcpy(dynamicStudent->name, "Priya");
 dynamicStudent->rollNo = 102;
 dynamicStudent->marks = 92.0;

 printf("Dynamic Student: %s, %d, %.1f\n", 
 dynamicStudent->name, dynamicStudent->rollNo, dynamicStudent->marks);

 free(dynamicStudent);
 dynamicStudent = NULL;

 printf("\n");
}

void demonstrateDoublePointer() {
 printf("=== Double Pointer (Pointer to Pointer) ===\n");

 int x = 100;
 int *p = &x;
 int **pp = &p; // Double pointer

 printf("Value of x: %d\n", x);
 printf("Using *p: %d\n", *p);
 printf("Using **pp: %d\n", **pp);

 // Practical use: Function that modifies a pointer
 printf("\nPractical use: Modifying pointer in function\n");

 void allocateMemory(int **ptr, int size) {
 *ptr = (int *)malloc(size * sizeof(int));
 if (*ptr != NULL) {
 for (int i = 0; i < size; i++) {
 (*ptr)[i] = i * 5;
 }
 }
 }

 int *arr = NULL;
 allocateMemory(&arr, 5); // Pass address of pointer

 printf("Dynamically allocated array: ");
 for (int i = 0; i < 5; i++) {
 printf("%d ", arr[i]);
 }
 printf("\n");

 free(arr);
 arr = NULL;

 printf("\n");
}

void demonstrateMemoryLeakAndDangling() {
 printf("=== Memory Leaks and Dangling Pointers ===\n");

 // Memory leak demonstration
 printf("Memory Leak Example:\n");
 void memoryLeakFunction() {
 int *p = (int *)malloc(100 * sizeof(int));
 // Without free(p), memory is leaked when function returns
 // For demonstration, we actually free it here
 free(p);
 }
 printf("Function allocated memory but didn't free - fixed with free()\n");

 // Dangling pointer demonstration
 printf("\nDangling Pointer Example:\n");
 int *danglingPtr = (int *)malloc(sizeof(int));
 *danglingPtr = 42;
 printf("Before free: *danglingPtr = %d\n", *danglingPtr);

 free(danglingPtr);
 // danglingPtr is now a dangling pointer!
 danglingPtr = NULL; // Prevent dangling pointer

 if (danglingPtr == NULL) {
 printf("After setting to NULL, pointer is safe to check\n");
 }

 printf("\nBest Practice: Always set pointer to NULL after free()\n");
 printf("\n");
}

/**
 * Java implementation demonstrating concepts analogous to C pointers
 * Note: Java doesn't have explicit pointers, but uses references which
 * behave similarly for objects and arrays
 */
import java.util.Arrays;

public class PointerConceptsDemo {

 public static void main(String[] args) {
 System.out.println("=========================================");
 System.out.println("Java: Analogous Concepts to C Pointers");
 System.out.println("=========================================\n");

 demonstrateBasicReferences();
 demonstrateArrayReferences();
 demonstrateDynamicMemoryAllocation();
 demonstrateStructLikeClasses();
 demonstrateReferenceParameters();
 demonstrate2DArrays();
 }

 // Similar to: int x = 42; int *p = &x;
 static void demonstrateBasicReferences() {
 System.out.println("=== Basic References (like Pointers) ===");

 // Primitive variables - passed by value
 int x = 42;
 System.out.println("int x = 42");
 System.out.println("Value of x: " + x);

 // Using wrapper class - passed by reference
 Integer refX = 42; // Auto-boxed Integer object
 System.out.println("Integer refX = 42 (auto-boxed)");
 System.out.println("refX.intValue(): " + refX.intValue());

 // Modifying through reference
 modifyValue(refX);
 System.out.println("After modifyValue: " + refX);

 System.out.println();
 }

 static void modifyValue(Integer val) {
 // This creates a new Integer object (immutable)
 val = 100;
 }

 // Similar to: int arr[5] = {10,20,30,40,50}; int *p = arr;
 static void demonstrateArrayReferences() {
 System.out.println("=== Array References ===");

 int[] arr = {10, 20, 30, 40, 50};
 int[] p = arr; // Similar to: int *p = arr;

 System.out.println("Array: " + Arrays.toString(arr));
 System.out.println("Using index arr[2]: " + arr[2]);
 System.out.println("Using pointer-style p[2]: " + p[2]);

 // Pointer arithmetic equivalent using array index
 System.out.println("\nPointer arithmetic equivalent:");
 System.out.println("*(p+1) style - p[1]: " + p[1]);
 System.out.println("*(p+2) style - p[2]: " + p[2]);

 // Iterate like pointer increment
 System.out.println("\nIterating with increment (like p++):");
 int i = 0;
 while (i < arr.length) {
 System.out.println("p[" + i + "] = " + p[i]);
 i++;
 }

 System.out.println();
 }

 // Similar to: int *arr = malloc(5 * sizeof(int));
 static void demonstrateDynamicMemoryAllocation() {
 System.out.println("=== Dynamic Memory Allocation ===");

 // Java's dynamic array - automatic, no explicit malloc
 int size = 5;
 int[] dynamicArray = new int[size]; // Similar to: malloc

 System.out.println("new int[5] (like malloc - NOT initialized):");
 System.out.println(Arrays.toString(dynamicArray)); // Contains 0s (default)

 // Initialize values
 for (int i = 0; i < size; i++) {
 dynamicArray[i] = (i + 1) * 10;
 }
 System.out.println("After initialization: " + Arrays.toString(dynamicArray));

 // Java equivalent to calloc (zero-initialized by default)
 int[] zeroArray = new int[5];
 System.out.println("\nZero-initialized (like calloc): " + Arrays.toString(zeroArray));

 // Reallocation equivalent - create new larger array
 int[] newArray = Arrays.copyOf(dynamicArray, 10); // Like realloc
 System.out.println("\nAfter Arrays.copyOf (like realloc): " + 
 "new length = " + newArray.length);

 // Memory is automatically garbage collected - no free() needed
 dynamicArray = null; // Eligible for GC

 System.out.println();
 }

 // Similar to: struct Student { char name[50]; int rollNo; float marks; };
 static class Student {
 String name;
 int rollNo;
 float marks;

 Student(String name, int rollNo, float marks) {
 this.name = name;
 this.rollNo = rollNo;
 this.marks = marks;
 }

 // Method to display - similar to print function
 void display() {
 System.out.println("Name: " + name + ", Roll No: " + rollNo + ", Marks: " + marks);
 }
 }

 static void demonstrateStructLikeClasses() {
 System.out.println("=== Classes as Structures (with Pointers) ===");

 // Create object - similar to: struct Student s1;
 Student s1 = new Student("Rahul", 101, 85.5f);

 // Reference to object - similar to: struct Student *ptr = &s1;
 Student ptr = s1;

 // Access members - similar to: ptr->name or (*ptr).name
 System.out.println("Using ptr.name (like ptr->name): " + ptr.name);
 System.out.println("Using ptr.rollNo: " + ptr.rollNo);
 System.out.println("Using ptr.marks: " + ptr.marks);

 // Modify through reference
 ptr.name = "Priya";
 System.out.println("\nAfter modification through ptr:");
 s1.display();

 // Dynamic allocation - similar to: malloc(sizeof(struct Student))
 Student dynamicStudent = new Student("Alex", 103, 78.0f);
 System.out.println("\nDynamically allocated Student: " + dynamicStudent.name);

 // No explicit free() needed - garbage collection handles it

 System.out.println();
 }

 // Similar to: void allocateMemory(int **ptr)
 static void demonstrateReferenceParameters() {
 System.out.println("=== Passing References to Modify Pointers ===");

 // Java doesn't have ** but we can use wrapper or arrays
 int[] pointerHolder = null; // Simulates int **ptr

 allocateMemory(pointerHolder, 5); // This won't work as expected

 // Correct way in Java - use an array wrapper
 int[][] pointerRef = {null};
 allocateMemoryCorrect(pointerRef, 5);

 int[] result = pointerRef[0];
 System.out.println("Allocated array: " + Arrays.toString(result));

 System.out.println();
 }

 // This doesn't work as expected - demonstrates Java's pass-by-value
 static void allocateMemory(int[] ptr, int size) {
 ptr = new int[size]; // Only modifies local copy
 }

 // Correct way - use array to simulate pointer-to-pointer
 static void allocateMemoryCorrect(int[][] ptrRef, int size) {
 ptrRef[0] = new int[size];
 for (int i = 0; i < size; i++) {
 ptrRef[0][i] = i * 5;
 }
 }

 static void demonstrate2DArrays() {
 System.out.println("=== 2D Arrays (Dynamic) ===");

 // Similar to: int **arr = malloc(rows * sizeof(int*));
 int rows = 3, cols = 4;
 int[][] matrix = new int[rows][cols];

 // Initialize
 int value = 1;
 for (int i = 0; i < rows; i++) {
 for (int j = 0; j < cols; j++) {
 matrix[i][j] = value++;
 }
 }

 System.out.println("3x4 Matrix:");
 for (int i = 0; i < rows; i++) {
 System.out.println(Arrays.toString(matrix[i]));
 }

 // Access like pointer arithmetic
 System.out.println("\nmatrix[1][2] (like *(*(matrix+1)+2)): " + matrix[1][2]);

 System.out.println("\nNote: No memory leaks in Java - GC handles deallocation!\n");
 }
}
